"use client";
import Link from "next/link";
import Image from "next/image";
import styles from "./styles.module.scss";
import { useState, useEffect, useRef, useCallback } from "react";
import Head from "next/head";
import axios from "axios";
import moment from "moment";

import { NextResponse } from "next/server";
import { writeFile } from "fs/promises";
import path from "path";

// In-memory data (replace with a database in a real application)
let articlesData = [
  {
    _id: "1",
    title: "Article 1",
    content: "Content 1",
    image: "/image1.jpg",
    date: "2024-01-01",
  },
  {
    _id: "2",
    title: "Article 2",
    content: "Content 2",
    image: "/image2.jpg",
    date: "2024-01-02",
  },
];

export async function GET() {
  try {
    return NextResponse.json(articlesData);
  } catch (error) {
    console.error("Error fetching articles:", error);
    return new NextResponse("Internal Server Error", { status: 500 });
  }
}

export async function POST(request: Request) {
  try {
    const formData = await request.formData();
    const title = formData.get("title") as string;
    const content = formData.get("content") as string;
    const imageFile = formData.get("image") as File | null;

    if (!title || !content) {
      return new NextResponse("Missing title or content", { status: 400 });
    }

    let imageName: string | null = null;
    let imagePath: string | null = null;

    if (imageFile) {
      const buffer = await imageFile.arrayBuffer();
      const bytes = new Uint8Array(buffer);
      imageName = `${Date.now()}-${imageFile.name}`; // Unique filename
      imagePath = path.join(process.cwd(), "public", "uploads", imageName); // Save to public/uploads
      await writeFile(imagePath, bytes); // Use fs/promises for async writeFile
    }

    const newArticle = {
      _id: Date.now().toString(), // Temporary ID
      title,
      content,
      image: imageName ? `/uploads/${imageName}` : "", // Store the relative path, ensure it's a string
      date: new Date().toISOString(),
    };

    articlesData = [...articlesData, newArticle]; // Update in-memory data

    return NextResponse.json(newArticle, { status: 201 }); // Return the new article
  } catch (error) {
    console.error("Error creating article:", error);
    return new NextResponse("Internal Server Error", { status: 500 });
  }
}

interface Article {
  _id: string;
  title: string;
  content: string;
  image: string; // Important: image must be a string
  date: string;
}

interface HomeAdBaiVietProps {}

const HomeAdBaiViet: React.FC<HomeAdBaiVietProps> = () => {
  const [isSidebarHidden, setIsSidebarHidden] = useState(false);
  const sidebarRef = useRef<HTMLElement | null>(null);
  const mainContentRef = useRef<HTMLElement | null>(null);

  const [articles, setArticles] = useState<Article[]>([]);
  const [newArticle, setNewArticle] = useState({
    title: "",
    image: "",
    content: "",
  });
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false); // Add loading state

  const toggleSidebar = useCallback(() => {
    setIsSidebarHidden((prevState) => !prevState);
  }, []);

  const updateClasses = useCallback(() => {
    const sidebar = sidebarRef.current;
    const mainContent = mainContentRef.current;

    if (sidebar && mainContent) {
      if (isSidebarHidden) {
        sidebar.classList.add(styles.hidden);
        mainContent.classList.add(styles.expanded);
      } else {
        sidebar.classList.remove(styles.hidden);
        mainContent.classList.remove(styles.expanded);
      }
    }
  }, [isSidebarHidden, styles.expanded, styles.hidden]);

  // Fetch articles effect
  useEffect(() => {
    const fetchArticles = async () => {
      setIsLoading(true); // Start loading
      try {
        const response = await axios.get("/api/articles");
        // Ensure that image is always a string, replace null with empty string
        const processedArticles = response.data.map((article: any) => ({
          ...article,
          image: article.image || "", // Ensure image is a string.
        }));
        setArticles(processedArticles);
      } catch (error: any) {
        console.error("Error fetching articles:", error);
        setErrorMessage("Failed to load articles. Please try again.");
      } finally {
        setIsLoading(false); // End loading regardless of success or failure
      }
    };

    fetchArticles();
  }, []); // Empty dependency array means this runs only once on mount

  useEffect(() => {
    updateClasses();
  }, [isSidebarHidden, updateClasses]);

  const handleInputChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    const { name, value } = e.target;
    setNewArticle((prevArticle) => ({ ...prevArticle, [name]: value }));
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedImage(e.target.files[0]);
    }
  };

  const createArticle = async () => {
    setErrorMessage(null);
    setSuccessMessage(null);
    setIsLoading(true); // Start loading during article creation

    try {
      const formData = new FormData();
      formData.append("title", newArticle.title);
      formData.append("content", newArticle.content);
      if (selectedImage) {
        formData.append("image", selectedImage);
      }

      const response = await axios.post("/api/articles", formData, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
      });

      // Optimistically update the articles state.  This assumes the API returns the newly created article.
      setArticles((prevArticles) => [
        ...prevArticles,
        {
          ...response.data,
          image: response.data.image || "", // Make sure the image is a string
        },
      ]);

      setNewArticle({ title: "", image: "", content: "" });
      setSelectedImage(null);
      setSuccessMessage("Article created successfully!");
    } catch (error: any) {
      console.error("Error creating article:", error);
      setErrorMessage(
        "Failed to create article. Please check the form and try again."
      );
    } finally {
      setIsLoading(false); // End loading
    }
  };

  const formatDate = (dateString: string) => {
    return moment(dateString).format("MMMM D, YYYY");
  };

  return (
    <>
      <Head>
        <link
          rel="stylesheet"
          href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.2/css/all.min.css"
          integrity="sha512-SnH5WK+bZxgPHs44uWIX+LLJAJ9/2PkPKZ5QiAj6Ta86w+fsb2TkcmfRyVX3pBnMFcV7oQPJkl9QevSCWr3W6A=="
          crossOrigin="anonymous"
          referrerPolicy="no-referrer"
        />
      </Head>
      <header className={styles.header}>
        <div className={styles.headerLeft}>
          <button className={styles.thanhKeo} onClick={toggleSidebar}>
            ☰
          </button>

          <div className={styles.logo}>
            <Image src="/QR.png" alt="Logo" width={40} height={40} />
          </div>
          <div className={styles.headerTitle}>SHOP</div>
        </div>

        <div className={styles.headerIconsRight}>
          <a href="">
            <i className="fas fa-sign-out-alt"></i>
          </a>
        </div>
      </header>

      <div className={styles.container}>
        <aside
          id="sidebar"
          className={`${styles.sidebar} ${
            isSidebarHidden ? styles.hidden : ""
          }`}
          ref={sidebarRef}
        >
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Bảng Điều Khiển
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Sản Phẩm
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Danh Mục Sản Phẩm
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="#" className={styles.sidebarLink}>
              Tổng Danh Thu
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Khách Hàng
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Nhân Viên
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="#" className={styles.sidebarLink}>
              Đánh Giá
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="#" className={styles.sidebarLink}>
              Đơn Hàng
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="#" className={styles.sidebarLink}>
              Bài Viết
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Khuyến Mãi
            </Link>
          </button>
        </aside>

        <main
          ref={mainContentRef}
          className={`${styles.mainContent} ${
            isSidebarHidden ? styles.expanded : ""
          }`}
        >
          <h1>Quản Lý Bài Viết</h1>

          {errorMessage && <div className={styles.error}>{errorMessage}</div>}
          {successMessage && (
            <div className={styles.success}>{successMessage}</div>
          )}

          <section className={styles.articlesSection}>
            <h2>Danh Sách Bài Viết</h2>
            {isLoading ? (
              <p>Loading articles...</p>
            ) : (
              <div className={styles.articleList}>
                {articles.map((article) => (
                  <div key={article._id} className={styles.articleItem}>
                    {article.image && (
                      <img
                        src={article.image} // Serve from backend
                        alt={article.title}
                        className={styles.articleImage}
                      />
                    )}
                    <h3>{article.title}</h3>
                    <p className={styles.articleDate}>
                      Ngày đăng: {formatDate(article.date)}
                    </p>
                    <p>{article.content.substring(0, 100)}...</p>
                    <Link href={`/article/${article._id}`}>Xem chi tiết</Link>
                  </div>
                ))}
              </div>
            )}
          </section>

          <section className={styles.createArticleSection}>
            <h2>Thêm Bài Viết Mới</h2>
            <div className={styles.formGroup}>
              <label htmlFor="title">Tiêu Đề:</label>
              <input
                type="text"
                id="title"
                name="title"
                value={newArticle.title}
                onChange={handleInputChange}
              />
            </div>
            <div className={styles.formGroup}>
              <label htmlFor="image">Ảnh:</label>
              <input
                type="file"
                id="image"
                name="image"
                onChange={handleImageChange}
              />
            </div>
            <div className={styles.formGroup}>
              <label htmlFor="content">Nội Dung:</label>
              <textarea
                id="content"
                name="content"
                value={newArticle.content}
                onChange={handleInputChange}
              />
            </div>
            <button
              onClick={createArticle}
              className={styles.createButton}
              disabled={isLoading}
            >
              {isLoading ? "Creating..." : "Tạo Bài Viết"}
            </button>
          </section>
        </main>
      </div>
    </>
  );
};

export default HomeAdBaiViet;
